{"code":"import json, re, pathlib
pat=re.compile('irish', re.I)

def extract_irish(obj):
    out=[]
    if isinstance(obj, list):
        for item in obj:
            out.extend(extract_irish(item))
    elif isinstance(obj, dict):
        # if this looks like a voice definition
        joined=' '.join([str(obj.get(k,'')) for k in obj.keys()])
        # check fields commonly used
        fields=[obj.get('label'), obj.get('name'), obj.get('language'), obj.get('accent'), obj.get('locale'), obj.get('tags')]
        s=' '.join([str(f) for f in fields if f is not None])
        if pat.search(s):
            out.append(obj)
        for v in obj.values():
            out.extend(extract_irish(v))
    return out

files=[
'/data/repos/storyteller/data/voices.index.json',
'/data/repos/storyteller/data/voices.11labs.json',
'/data/repos/storyteller/data/voices.lmnt.json'
]
for f in files:
    data=json.loads(pathlib.Path(f).read_text())
    irish=extract_irish(data)
    # dedupe by json string
    seen=set(); uniq=[]
    for o in irish:
        s=json.dumps(o, sort_keys=True)
        if s not in seen:
            seen.add(s); uniq.append(o)
    print(f, len(uniq))
    # print minimal id/name/label
    for o in uniq[:50]:
