function.arguments:
{"code":"import pandas as pd
pet = pd.read_csv('/data/Pet Care 2023 Weekly Financials.csv')
pet.columns=[c.strip() for c in pet.columns]
pet['week_num']=pet['Purchase Dates (2023)'].str.extract(r'(\d+)').astype(int)
def money_to_float(s):
    return float(str(s).replace('$','').replace(',','').strip())
pet['Total Weekly Revenue']=pet['Total Weekly Revenue  Week'].apply(money_to_float)
pet_first_half = pet.loc[pet['week_num']<=26,'Total Weekly Revenue'].sum()
pet_first_half
"}

